mapper.select:
SELECT COUNT(*)
FROM sys_ai_feedback
WHERE feedback_type = #{feedbackType}

SELECT f.id, f.conversation_id AS conversationId, f.user_id AS userId, f.user_from AS userFrom, f.feedback_type AS feedbackType, f.dislike_reason AS dislikeReason, f.comment, f.create_time AS createTime, LEFT(c.question, 100) AS question, LEFT(c.answer, 200) AS answerSummary, c.model, c.sources AS sourcesJson FROM sys_ai_feedback f LEFT JOIN sys_ai_conversation c ON f.conversation_id = c.id
AND f.feedback_type = #{feedbackType}
AND f.dislike_reason = #{dislikeReason}
AND f.user_id = #{userId}
AND f.create_date >= #{startDate}
AND f.create_date <= #{endDate}
ORDER BY f.create_time DESC
